# solarsentinel_kaggle.py

import os
import sys
import re
import json
import subprocess
import base64
import shutil
import logging
import warnings

# Aggressive silence for the controller script
logging.disable(logging.INFO)
try:
    from absl import logging as absl_logging
    absl_logging.set_verbosity(absl_logging.ERROR)
except ImportError:
    pass
warnings.filterwarnings("ignore")

# Base64 encoded code to avoid escape character issues
SUBMISSION_B64 = """"""
TRAINER_B64 = """"""
BENCHMARK_B64 = """"""

def setup():
    print("Initializing SolarSentinel Training Environment (PARALLEL OPTIMIZED)...")
    os.makedirs("snapshots", exist_ok=True)
    
    with open("submission.py", "wb") as f:
        f.write(base64.b64decode(SUBMISSION_B64))
        
    with open("self_play_trainer.py", "wb") as f:
        f.write(base64.b64decode(TRAINER_B64))
        
    with open("benchmark.py", "wb") as f:
        f.write(base64.b64decode(BENCHMARK_B64))
        
    # Establish baseline for Phase 0
    shutil.copy2("submission.py", "snapshots/agent_v0.py")
    print("Baseline snapshot established at snapshots/agent_v0.py")

    print("Installing dependencies...")
    # Upgrade to latest kaggle-environments for orbit_wars stability
    subprocess.run([sys.executable, "-m", "pip", "install", "--upgrade", "--no-cache-dir", "kaggle-environments>=1.28.0", "numpy", "torch"], 
                   stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL, check=True)
    
    print("Verified environments Ready.")


def safe_run(cmd, phase_name):
    print(f"\n{'='*70}\n[PHASE {phase_name}] Initiating...\n{'='*70}")
    try:
        subprocess.run(cmd, check=True)
    except subprocess.CalledProcessError as e:
        print(f"\n[ERROR] Phase {phase_name} failed with exit code {e.returncode}. Proceeding to next phase...")
    except Exception as e:
        print(f"\n[ERROR] Phase {phase_name} encountered an unexpected error: {e}. Proceeding to next phase...")


def read_cfg_from_submission():
    if not os.path.exists("submission.py"): return {}
    with open("submission.py", "r") as f:
        src = f.read()
    match = re.search(r'CFG = \{(.*?)\}', src, re.DOTALL)
    if not match: return {}
    lines = match.group(1).split("\n")
    cfg = {}
    for line in lines:
        m = re.search(r'"([^"]+)":\s*([0-9\.\-]+)', line)
        if m: cfg[m.group(1)] = float(m.group(2))
    return cfg


def get_mu_estimate(wr):
    if wr > 0.85: return "300-400"
    if wr > 0.70: return "150-300"
    return "0-150"


def run():
    # Phase 0: Establishing Baseline Performance
    safe_run([sys.executable, "benchmark.py", "--agent-a", "submission.py", 
              "--agent-b", "snapshots/agent_v0.py", "--quick"], "0: BASELINE BENCHMARK")

    # Phase 1: Initial Parameter Exploration
    safe_run([sys.executable, "self_play_trainer.py", "evolve", 
              "--generations", "25", "--pop-size", "10", 
              "--games-per-eval", "20", "--sigma", "0.25", 
              "--sigma-decay", "0.93"], "1: ACCELERATED PARAMETER EVOLUTION")
    
    # Phase 2: League Self-Play Arena
    safe_run([sys.executable, "self_play_trainer.py", "arena", 
              "--games", "600", "--snapshot-every", "50", 
              "--pool-size", "8", "--elo-k", "24"], "2: LEAGUE SELF-PLAY ARENA")

    # Phase 3: Fine-Tuning after Self-Play Exposure
    safe_run([sys.executable, "self_play_trainer.py", "evolve", 
              "--generations", "15", "--pop-size", "8", 
              "--games-per-eval", "24", "--sigma", "0.10", 
              "--sigma-decay", "0.90"], "3: POST-ARENA FINE-TUNING")

    # +++ FINAL VERIFICATION +++
    print(f"\n{'='*70}\n[FINAL VERIFICATION] Evaluating Performance Gain...\n{'='*70}")
    safe_run([sys.executable, "benchmark.py", "--agent-a", "submission.py", 
              "--agent-b", "snapshots/agent_v0.py", "--games", "30"], "FINAL QUALITY CHECK")
    
    # Load and Report
    win_rate = 0.0
    p_val = 1.0
    if os.path.exists("benchmark_results.json"):
        with open("benchmark_results.json", "r") as f:
            res = json.load(f)
            win_rate = res.get("winrate_a", 0.0)
            p_val = res.get("p_value", 1.0)
            print(f"\nFinal Win Rate vs Baseline: {win_rate*100:.1f}% (p={p_val:.4f})")
            if win_rate < 0.70:
                print("\nWARNING: Agent may not have improved enough. Consider re-running.")
    
    # CFG Printout
    print("\n--- FINAL OPTIMIZED PARAMETERS ---")
    cfg = read_cfg_from_submission()
    for k, v in cfg.items():
        print(f"  {k:<30}: {v:.4f}")
    
    # Validity Check
    print("\nVerifying submission.py integrity...")
    try:
        subprocess.run([sys.executable, "-c", "import submission; print('Agent loads OK')"], 
                       check=True, capture_output=True)
    except Exception:
        print("\n[CRITICAL ERROR] submission.py is corrupted! Restoring from baseline...")
        shutil.copy2("snapshots/agent_v0.py", "submission.py")
    
    # Final Summary
    elo_val = "N/A"
    if os.path.exists("elo_history.json"):
        with open("elo_history.json", "r") as f:
            elo_data = json.load(f)
            elo_val = elo_data.get("ratings", {}).get("current", "N/A")
            if isinstance(elo_val, float): elo_val = f"{elo_val:.0f}"

    print(f"\n{'='*70}")
    print("=== TRAINING COMPLETE ===")
    print(f"Best ELO achieved: {elo_val}")
    print(f"Win rate vs baseline: {win_rate*100:.1f}%")
    print(f"Estimated Kaggle μ improvement: +{get_mu_estimate(win_rate)}μ expected")
    print(f"{'='*70}\n")

if __name__ == "__main__":
    setup()
    run()
